def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    """
    {The algorithm chooses the next node based on a weighted combination of inverse distance, a reward for nodes distant from the last visited node, and a stability adjustment to delay nodes revisited by trucks.}
    """
    # Step 1: Calculate inverse distances for each unvisited node.
    inverse_distances = {node: 1.0 / (distance_matrix[current_node, node] + 1.e-5) for node in unvisited_nodes}

    # Step 2: Reward nodes far from the last visited node by the current truck.
    last_visited_distance_reward = {node: distance_matrix[truck_nodes[-1], node] for node in unvisited_nodes}

    # Step 3: Adjust for stability by checking recent visits and delaying revisiting.
    stability_penalty = {node: 0.9 if node in truck_nodes else 0.1 for node in unvisited_nodes}

    # Step 4: Compute a new combined priority score for selection.
    scores = {node: (0.4 * inverse_distances[node] + 0.4 * last_visited_distance_reward[node] + 0.2 * stability_penalty[node])
              for node in unvisited_nodes}

    # Step 5: Select the node with the highest priority score.
    next_node = max(scores, key=scores.get)

    return next_node
